// إنشاء رقم إصدار التطبيق
uint32_t appVersion = VK_MAKE_VERSION(1, 0, 0);
// النتيجة: (1 << 22) | (0 << 12) | 0 = 4194304

// إنشاء رقم إصدار المحرك
uint32_t engineVersion = VK_MAKE_VERSION(2, 5, 3);

// الاستخدام في VkApplicationInfo
VkApplicationInfo appInfo = {};
appInfo.applicationVersion = VK_MAKE_VERSION(1, 2, 3);
appInfo.engineVersion = VK_MAKE_VERSION(4, 5, 6);
